  ('elementary-8b44517b-moex-00349', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '社會秩序維護法規定，無正當理由，跟追他人，經勸阻不聽者，處新臺幣3千元以下罰鍰或申誡。關於該 條所涉之人民基本權利，依司法院大法官解釋，下列敘述何者錯誤？', '["該規定保障人民之新聞採訪自由", "該規定保障人民免於身心傷害之身體權", "該規定保障人民生活私密領域不受侵擾之自由，即使在公共場域中人民亦享有此權利", "該規定限制人民的行動自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
